(function(){'use strict';document.addEventListener('DOMContentLoaded',function(){var e=document.querySelector('[data-fp-carousel]');if(!e)return;var s=new Splide(e,{type:'slide',perPage:4,perMove:1,gap:'20px',arrows:false,pagination:false});s.mount();var p=document.querySelector('[data-fp-prev]'),n=document.querySelector('[data-fp-next]');if(p)p.addEventListener('click',function(){s.go('<')});if(n)n.addEventListener('click',function(){s.go('>')})})})();
